export const JournalDayDetailSchema = z.object({ "object_id": z.string().uuid().describe("Identity of a canonical object (client-minted UUIDv7)."), "date": z.string().date() }).describe("Non-content metadata for a `journal_day` object (§6.5 surfaces): the calendar date this\nday's flow belongs to. A `journal_day` owns ONE day's `content_units`; the *journal* is the\nview over these objects ORDER BY date, and an object's appearance on a day is an\n`Embed{target: Object}` unit. The date is object identity (`UNIQUE(space_id, date)` in SQL),\nnot patchable content — re-dating is a deliberate §6.5 content-move op, never a column edit.\n`NaiveDate` serde-round-trips as ISO `YYYY-MM-DD`; chrono is built clock-free (the date is\nPASSED IN), so the core stays pure.");

export const LayoutStepSchema = z.enum(["none","small","medium","large"]).describe("A closed, layout-relative spacing step (never device pixels, §2.1) — the reserve between a brace and\nthe span it embraces. A style skin maps `Small → 0.5em`, etc. The v1 placement knob.");

