export const ProvenanceDerivationSchema = z.object({ "provenance_id": z.string().uuid().describe("Identity of a provenance row (glue-minted UUIDv7)."), "derived_from_provenance_id": z.string().uuid().describe("Identity of a provenance row (glue-minted UUIDv7).") }).describe("One edge of the provenance derivation chain (§6.1) — a typed, FK-checked join row\nrather than a `uuid[]`, because provenance is the trust spine.");

