export const ToggleExpressionPlacementInputSchema = z.object({ "expected_revision": z.number().int().gte(0), "unit_id": z.string().uuid().describe("Identity of a content unit (`content_units` row, §6.0b) — what annotations\nanchor to, AI candidates target, and edges point at."), "expression_id": z.string().uuid().describe("Identity of a `MathExpression` (§6.3a). Minted in content, presentation-\nindependent, and unique workspace-wide (the copy-mints-fresh rule, §6.3a).\nLives inside serialized `UnitContent`, not its own table."), "display_unit_id": z.string().uuid().describe("Identity of a content unit (`content_units` row, §6.0b) — what annotations\nanchor to, AI candidates target, and edges point at."), "trailing_unit_id": z.string().uuid().describe("Identity of a content unit (`content_units` row, §6.0b) — what annotations\nanchor to, AI candidates target, and edges point at.") }).describe("`toggle_expression_placement` payload — the `$$`/`$` gesture. The op infers the direction\nfrom the unit: a prose unit holding the inline atom → *promote* to a display `Math` unit,\nsplitting the prose around it (`display_unit_id` = the math unit; `trailing_unit_id` = the\nafter-prose half when non-empty); a standalone `Math` unit → *demote*, folding the atom back\ninto an adjacent prose sibling (the two new ids are unused on demote).");

